import { createClient } from '@/utils/supabase/server'
import { z } from 'zod'
import { getAuthUserInfo } from './getUser'
import { SelectedOption } from '@/app/lib/cart.types'

type AddCartParams = {
  productId: string
  optionData: SelectedOption
  quantity: number
}

const productSchema = z.object({
  name: z.string(),
  price: z.number(),
  thumbnail_image: z.string().nullable().optional(),
  options: z.any().nullable().optional(),
  discount_rate: z.number().nullable().optional(),
})

export async function addCartItem({
  productId,
  optionData,
  quantity,
}: AddCartParams) {
  const auth = await getAuthUserInfo()

  if (!auth?.id) {
    throw new Error('로그인이 필요합니다.')
  }

  const supabase = await createClient()

  const { data: existingItems, error: selectError } = await supabase
    .from('cart_items')
    .select('id, quantity, selected_options')
    .eq('user_id', auth.id)
    .eq('product_id', productId)

  if (selectError) {
    throw new Error(selectError.message)
  }
  // JS에서 옵션 검증 (객체 키 순서 등의 문제 방지를 위해 문자열 비교 혹은 깊은 비교)
  const existingItem = existingItems?.find(
    (item) =>
      JSON.stringify(item.selected_options) === JSON.stringify(optionData),
  )

  // 제품이 이미 있으면 갯수 추가
  if (existingItem) {
    const { error: updateError } = await supabase
      .from('cart_items')
      .update({
        quantity: existingItem.quantity + quantity,
      })
      .eq('id', existingItem.id)

    if (updateError) {
      throw new Error(updateError.message)
    }

    return
  }

  const { error } = await supabase.from('cart_items').insert({
    user_id: auth.id,
    product_id: productId,
    selected_options: optionData,
    quantity,
  })

  if (error) {
    throw new Error(error.message)
  }
}

